const { body } = $input.first().json;

let messageBody = body?.Body || '';

const MAX_LENGTH = 2000;
if (messageBody.length > MAX_LENGTH) {
  messageBody = messageBody.substring(0, MAX_LENGTH);
}

return [{
  json: {
    conversationSid: body?.ConversationSid || '',
    messageBody,
    author: body?.Author || '',
    messageSid: body?.MessageSid || '',
    accountSid: body?.AccountSid || '',
    eventType: body?.EventType || '',
  },
}];

const message = $json.messageBody || '';

if (message.startsWith('[system]')) {
  return [{ json: { ...$json, safe: true, reason: '' } }];
}

const INJECTION = [
  /ignore\s+(all\s+)?(previous|prior|above|earlier)\s+(instructions|rules|prompts|guidelines)/i,
  /disregard\s+(all\s+)?(previous|prior|above|your)\s+(instructions|rules|prompts)/i,
  /forget\s+(all\s+)?(previous|prior|your)\s+(instructions|rules|context|training)/i,
  /new\s+(instructions|rules|prompt|directive)\s*:/i,
  /override\s+(previous|all|your)\s+(instructions|rules|settings)/i,
  /you\s+are\s+now\s+(a|an|the|my)\s/i,
  /from\s+now\s+on\s+(you|ignore|forget|act)/i,
  /\[system\]|\[INST\]|<\|im_start\|/i,
  /\bsystem\s*:\s/i,
];

const JAILBREAK = [
  /\bdan\s*mode\b/i,
  /\bjailbreak\b/i,
  /\bdeveloper\s*mode\b/i,
  /\bgod\s*mode\b/i,
  /pretend\s+(you|that)\s+(have\s+no|don't\s+have|are\s+not\s+bound|are\s+free|can\s+do\s+anything)/i,
  /act\s+(as\s+if|like)\s+(you\s+)?(have\s+no|there\s+are\s+no)\s+(rules|restrictions|limitations)/i,
  /bypass\s+(your|all|the|any)\s+(restrictions|rules|filters|safety|guidelines)/i,
  /enable\s+(unrestricted|unfiltered|uncensored)\b/i,
];

const EXTRACTION = [
  /what\s+are\s+your\s+(instructions|rules|guidelines|system\s*prompt)/i,
  /(show|reveal|display|print|output|repeat|tell\s+me)\s+(me\s+)?(your|the)\s+(system\s*prompt|instructions|initial\s*prompt|original\s*prompt)/i,
  /what\s+(were\s+you|was\s+your)\s+(told|instructed|programmed|trained|configured)/i,
];

const ABUSE = [
  /\b(fuck\s*you|go\s+fuck|motherfuck|piece\s+of\s+shit)\b/i,
  /\b(kill\s+(yourself|yourselves)|i('ll|\s+will)\s+(kill|hurt|harm|attack)\s+you)\b/i,
];

const CODE_INJECTION = [
  /<script[\s>]/i,
  /javascript\s*:/i,
  /on(load|error|click|mouseover)\s*=/i,
];

const checks = [
  { patterns: INJECTION, category: 'prompt_injection' },
  { patterns: JAILBREAK, category: 'jailbreak' },
  { patterns: EXTRACTION, category: 'data_extraction' },
  { patterns: ABUSE, category: 'abuse' },
  { patterns: CODE_INJECTION, category: 'code_injection' },
];

for (const { patterns, category } of checks) {
  for (const pattern of patterns) {
    if (pattern.test(message)) {
      return [{ json: { ...$json, safe: false, reason: category } }];
    }
  }
}

return [{ json: { ...$json, safe: true, reason: '' } }];

// ── Client routing table ───────────────────────────────────
// Add new clients here. Each entry maps to an AI webhook.
const ROUTING = {
  digishares: {
    webhookUrl: '__AI_WEBHOOK_URL_DIGISHARES__',
    authHeader: 'DigiSharesChatbot',
  },
  // clientB: {
  //   webhookUrl: 'https://...',
  //   authHeader: '',
  // },
};

// Parse client_id from author identity: 'digishares_user_xxx' → 'digishares'
// Backwards compat: 'user_xxx' (no prefix) → 'digishares'
const author = $json.author || '';
const clientId = author.includes('_user_')
  ? author.split('_user_')[0]
  : 'digishares';

const route = ROUTING[clientId];

if (!route) {
  return [];
}

return [{ json: { ...$json, clientId, webhookUrl: route.webhookUrl } }];

const aiResponse = $json;
const conversationSid = $('Extract Message Data').first().json.conversationSid;

let botReply = aiResponse.reply || aiResponse.message || aiResponse.output || aiResponse.text || '';

if (!botReply && typeof aiResponse === 'string') {
  botReply = aiResponse;
}

if (!botReply) {
  botReply = 'Sorry, I could not generate a response.';
}

return [{
  json: { conversationSid, botReply },
}];

const conversationSid = $json.conversationSid;
const reason = $json.reason || 'policy';

const botReply = "I'm here to help you with your questions. Could you please rephrase your message?";

return [{ json: { conversationSid, botReply } }];
